  "verses": [
    {
      "n": 25,
      "column": "left",
      "text": "Un Pekaüis / Remalijus definitā Gaddā Jotama Ustiju winna Leel-Kunga Dehls/ dar- Dehla.\nrija weenn Derribu prett winnu/\nun kawe to eekfch Samarijas\nceksch ta Kehnixa Namuna Pa-\ngalnja/ ar Argobu un ar Arju/\nun ar winnu bija peezeefmits\nWihru no Gileada Behrneem/\nun nokawe to/ un tas tappe par\nKehnixu winna Weetâ."
    },
    {
      "n": 26,
      "column": "left",
      "text": "Un kas wehl no Peka-\nus Leetahm atleek/ un wifs/ ko\nwiꞥſch irr darrıjs/ raugi/ tas irr\nraksthts to Israëta Kehnixu\nLaiku-Grahmata."
    },
    {
      "n": 27,
      "column": "left",
      "text": "Peektādefiniti ohtrā Gad-\nda Asarijus ta Kehnixa no Juh-\nda/ tappē Pekaüis Remalijus\nDehls par Kehnixu par Israëlu\neeksch Samarijas/ (un walđi-\nja) diwidefmits Gaddus."
    },
    {
      "n": 28,
      "column": "left",
      "text": "Un wiꞥſch darrıja / kas\ntam KUNGAM ne patikke/\nwiꞥſch ne atstahjehs no Jerobea-\nma Neebata Dehla Grehkeem/\nkas Israëlu grehkoht darrıjs."
    },
    {
      "n": 29,
      "column": "left",
      "text": "Pekaüfa ta Israëka\nKehnixa Laikā atnahze Tiglat\nPillefers tas Kehnisch no Af-\nsirtjas/ un usnehme Jönn/ un\nAbel Bet-Meaku/un Janon/ un\nRedes/ un Azoru/ un Gileadu/\nun Galileju/ un wiffu Nawtata\nSemni/ un nowedde tohs ue\nAffiriju."
    },
    {
      "n": 30,
      "column": "left",
      "text": "Un Oseüs Ella Dehls dar-\nrija weenn Derribu prett Peka-\nusu Remalijus Dehlu/ un kawe\nto/ un nokawe to/ un tappē par\nKehnixu winna Weetâ/ divi-"
    },
    {
      "n": 31,
      "column": "right",
      "text": "Un kas wehl no Pekaüf\nLeetahm atleek/ un wifs/ ko\nwiꞥſch irr darrıjs/ raugi/ tas i\nraksthts to Israëta Kehnixu\nLaiku-Grahmata."
    },
    {
      "n": 32,
      "column": "right",
      "text": "Ohtrā Gaddā Pekaüf\nRemalijus Dehla ta Israë-\nKehnixa / tappē Jotams Ustiju\nDehls par Kehnixu pahr Juhdu"
    },
    {
      "n": 33,
      "column": "right",
      "text": "Diwidefmits peezeus Ga-\ndus wezz bija wiꞥſch/ kad win-\npar Kehnixu tappē/ un walđi-\nfefchpadefmitē Gaddus Jeru-\nlemē/ un winna Mahteı bi-\nJerusa Wahrdā/ Zadaka Meitā"
    },
    {
      "n": 34,
      "column": "right",
      "text": "Un wiꞥſch darrıja / ko\ntam KUNGAM labbi patikke-\npehz wiffu/ ko winna Tehu-\nUstius bij darrıjs."
    },
    {
      "n": 35,
      "column": "right",
      "text": "Tee Augstumi ween\ntappē nopohstiti/ tee Laudis u-\npureja un kwehpınaja wehl\nteem Augstumeem. Schis u-\ntattıja tahs angstas Wahrtis p-\nta KUNGA Namuna."
    },
    {
      "n": 36,
      "column": "right",
      "text": "Un kas wehl no Jotam\nLeetahm atleek/ un wifs/\nwiꞥſch irr darrıjs/ tas irr ra-\nstihts to Kehnixu no Juhda Le-\ntu -Grahmata."
    },
    {
      "n": 37,
      "column": "right",
      "text": "Tanni Laikā fahze t-\nKUNGGS eeksch Juhda fuhtt-\nRezinu to Sihreu Kehnixu/\nPekaüfu Remalijus Dehlu."
    },
    {
      "n": 38,
      "column": "right",
      "text": "Un Jotams aismitge\nfatveein Tehweem/ un tappē p-\nfarveem Tehweem aprakts Da-\nwida fatva Tehwa Pilli."
    }
  ],
  "confidence": "high",
  "notes": ""
}
